// Create store { count: 0, name: 'Zustand' }
// Subscribe to log count on every change
// setState({ count: 1 })
// setState({ count: 2 })
// Select name and log it

exercises.solution:
function createStore(initialState) {
  let state = { ...initialState };
  let listeners = [];

  return {
    getState: () => state,
    setState: (partial) => {
      state = { ...state, ...partial };
      listeners.forEach(fn => fn(state));
    },
    select: (selectorFn) => selectorFn(state),
    subscribe: (listener) => {
      listeners.push(listener);
      return () => { listeners = listeners.filter(fn => fn !== listener); };
    }
  };
}

const store = createStore({ count: 0, name: 'Zustand' });
store.subscribe((s) => console.log('Count changed: ' + s.count));
store.setState({ count: 1 });
store.setState({ count: 2 });
console.log('Name: ' + store.select(s => s.name));

