// Simulate with staleTime = 1000ms
// Fetch, then fetch again (simulating within staleTime), then after staleTime

exercises.solution:
function createQueryCache() {
  const cache = {};

  return {
    fetch: (key, fetchFn, staleTime) => {
      const entry = cache[key];
      const now = Date.now();

      if (entry && (now - entry.timestamp) < staleTime) {
        console.log('FRESH: ' + key);
        return entry.data;
      }

      console.log('STALE/MISS: ' + key);
      const data = fetchFn();
      cache[key] = { data, timestamp: now };
      return data;
    },
    // Helper to simulate time passing
    expireEntry: (key) => {
      if (cache[key]) cache[key].timestamp = 0;
    }
  };
}

const qc = createQueryCache();
console.log('Result: ' + qc.fetch('users', () => 'UserList', 1000));
console.log('Result: ' + qc.fetch('users', () => 'UserList', 1000));
qc.expireEntry('users');
console.log('Result: ' + qc.fetch('users', () => 'UserListV2', 1000));

